changeSet.sql:
-- 1) Sauvegarde des données actuelles IF OBJECT_ID('tempdb..#SaveUsers') IS NOT NULL DROP TABLE #SaveUsers;
SELECT * INTO #SaveUsers FROM Utilisateur WHERE LOWER(LTRIM(RTRIM(login))) IN (N'admin', N'aminata.sow', N'oumar.ba');
-- 2) Suppression des liaisons UtilisateurRole puis des comptes DELETE ur FROM UtilisateurRole ur INNER JOIN Utilisateur u ON u.id = ur.id_utilisateur WHERE LOWER(LTRIM(RTRIM(u.login))) IN (N'admin', N'aminata.sow', N'oumar.ba');
DELETE FROM Utilisateur WHERE LOWER(LTRIM(RTRIM(login))) IN (N'admin', N'aminata.sow', N'oumar.ba');
-- 3) Réinitialiser le compteur IDENTITY DBCC CHECKIDENT('Utilisateur', RESEED, 0);
-- 4) Réinsérer avec id explicites SET IDENTITY_INSERT Utilisateur ON;
INSERT INTO Utilisateur ( id, login, mot_de_passe_hash, nom_complet, email, telephone, actif, nombre_echecs, version, code_agence ) SELECT 1, login, mot_de_passe_hash, nom_complet, email, telephone, ISNULL(actif, 1), 0, 0, code_agence FROM #SaveUsers WHERE LOWER(LTRIM(RTRIM(login))) = N'admin';
INSERT INTO Utilisateur ( id, login, mot_de_passe_hash, nom_complet, email, telephone, actif, nombre_echecs, version, code_agence ) SELECT 2, login, mot_de_passe_hash, nom_complet, COALESCE(email, N'aminata.sow@microfina.com'), COALESCE(telephone, N'22260101'), ISNULL(actif, 1), 0, 0, code_agence FROM #SaveUsers WHERE LOWER(LTRIM(RTRIM(login))) = N'aminata.sow';
INSERT INTO Utilisateur ( id, login, mot_de_passe_hash, nom_complet, email, telephone, actif, nombre_echecs, version, code_agence ) SELECT 3, login, mot_de_passe_hash, nom_complet, COALESCE(email, N'oumar.ba@microfina.com'), COALESCE(telephone, N'22260202'), ISNULL(actif, 1), 0, 0, code_agence FROM #SaveUsers WHERE LOWER(LTRIM(RTRIM(login))) = N'oumar.ba';
SET IDENTITY_INSERT Utilisateur OFF;
-- 5) Recaler le compteur pour que les prochaines créations reprennent à 4 DBCC CHECKIDENT('Utilisateur', RESEED, 3);
-- 6) Recréer les liaisons UtilisateurRole (login-based, safe when users are absent) INSERT INTO UtilisateurRole (id_utilisateur, id_role) SELECT u.id, r.id FROM Utilisateur u CROSS JOIN Role r WHERE LOWER(LTRIM(RTRIM(u.login))) = N'admin' AND r.code_role = N'ADMIN' AND NOT EXISTS (SELECT 1 FROM UtilisateurRole ur WHERE ur.id_utilisateur = u.id AND ur.id_role = r.id);
INSERT INTO UtilisateurRole (id_utilisateur, id_role) SELECT u.id, r.id FROM Utilisateur u CROSS JOIN Role r WHERE LOWER(LTRIM(RTRIM(u.login))) = N'aminata.sow' AND r.code_role = N'AGENT_CREDIT' AND NOT EXISTS (SELECT 1 FROM UtilisateurRole ur WHERE ur.id_utilisateur = u.id AND ur.id_role = r.id);
INSERT INTO UtilisateurRole (id_utilisateur, id_role) SELECT u.id, r.id FROM Utilisateur u CROSS JOIN Role r WHERE LOWER(LTRIM(RTRIM(u.login))) = N'oumar.ba' AND r.code_role = N'COMITE_CREDIT' AND NOT EXISTS (SELECT 1 FROM UtilisateurRole ur WHERE ur.id_utilisateur = u.id AND ur.id_role = r.id);
-- Nettoyage DROP TABLE #SaveUsers;
